   109→// --- HELPER FUNCTIONS ---
   110→export function extractRecordId(url: string | null | undefined): string | null {
   111→  if (!url) return null;
   112→  // Extrahiere die letzten 24 Hex-Zeichen mit Regex
   113→  const match = url.match(/([a-f0-9]{24})$/i);
   114→  return match ? match[1] : null;
   115→}
   116→
   117→export function createRecordUrl(appId: string, recordId: string): string {
   118→  return `https://my.living-apps.de/rest/apps/${appId}/records/${recordId}`;
   119→}
   120→
   121→async function callApi(method: string, endpoint: string, data?: any) {
   122→  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
   123→    method,
   124→    headers: { 'Content-Type': 'application/json' },
   125→    credentials: 'include',  // Nutze Session Cookies für Auth
   126→    body: data ? JSON.stringify(data) : undefined
   127→  });
   128→  if (!response.ok) throw new Error(await response.text());
   129→  // DELETE returns often empty body or simple status
   130→  if (method === 'DELETE') return true;
   131→  return response.json();
   132→}
   133→
   134→/** Upload a file to LivingApps. Returns the file URL for use in record fields. */
   135→export async function uploadFile(file: File | Blob, filename?: string): Promise<string> {
   136→  const formData = new FormData();
   137→  formData.append('file', file, filename ?? (file instanceof File ? file.name : 'upload'));
   138→  const res = await fetch(`${API_BASE_URL}/files`, {
   139→    method: 'POST',
   140→    credentials: 'include',
   141→    body: formData,
   142→  });
   143→  if (!res.ok) throw new Error(`File upload failed: ${res.status}`);
   144→  const data = await res.json();
   145→  return data.url;
   146→}
