   362→## src/hooks/useDashboardData.ts
   363→```
   364→import { useState, useEffect, useMemo, useCallback } from 'react';
   365→import type { Aktivitaeten, Stimmungskategorien, TaeglicheStimmung, PositiveMomente } from '@/types/app';
   366→import { LivingAppsService } from '@/services/livingAppsService';
   367→
   368→export function useDashboardData() {
   369→  const [aktivitaeten, setAktivitaeten] = useState<Aktivitaeten[]>([]);
   370→  const [stimmungskategorien, setStimmungskategorien] = useState<Stimmungskategorien[]>([]);
   371→  const [taeglicheStimmung, setTaeglicheStimmung] = useState<TaeglicheStimmung[]>([]);
   372→  const [positiveMomente, setPositiveMomente] = useState<PositiveMomente[]>([]);
   373→  const [loading, setLoading] = useState(true);
   374→  const [error, setError] = useState<Error | null>(null);
   375→
   376→  const fetchAll = useCallback(async () => {
   377→    setError(null);
   378→    try {
   379→      const [aktivitaetenData, stimmungskategorienData, taeglicheStimmungData, positiveMomenteData] = await Promise.all([
   380→        LivingAppsService.getAktivitaeten(),
   381→        LivingAppsService.getStimmungskategorien(),
   382→        LivingAppsService.getTaeglicheStimmung(),
   383→        LivingAppsService.getPositiveMomente(),
   384→      ]);
   385→      setAktivitaeten(aktivitaetenData);
   386→      setStimmungskategorien(stimmungskategorienData);
   387→      setTaeglicheStimmung(taeglicheStimmungData);
   388→      setPositiveMomente(positiveMomenteData);
   389→    } catch (err) {
   390→      setError(err instanceof Error ? err : new Error('Fehler beim Laden der Daten'));
   391→    } finally {
   392→      setLoading(false);
   393→    }
   394→  }, []);
   395→
   396→  useEffect(() => { fetchAll(); }, [fetchAll]);
   397→
   398→  const aktivitaetenMap = useMemo(() => {
   399→    const m = new Map<string, Aktivitaeten>();
   400→    aktivitaeten.forEach(r => m.set(r.record_id, r));
   401→    return m;
   402→  }, [aktivitaeten]);
   403→
   404→  const stimmungskategorienMap = useMemo(() => {
   405→    const m = new Map<string, Stimmungskategorien>();
   406→    stimmungskategorien.forEach(r => m.set(r.record_id, r));
   407→    return m;
   408→  }, [stimmungskategorien]);
   409→
   410→  return { aktivitaeten, setAktivitaeten, stimmungskategorien, setStimmungskategorien, taeglicheStimmung, setTaeglicheStimmung, positiveMomente, setPositiveMomente, loading, error, fetchAll, aktivitaetenMap, stimmungskategorienMap };
   411→}
   412→```
