export function extractRecordId(url: string | null | undefined | unknown): string | null {
  if (!url) return null;
  // Handle object responses from API (e.g. applookup fields return {value, label} or similar)
  if (typeof url === 'object') {
    const obj = url as Record<string, unknown>;
    const candidate = obj['value'] ?? obj['url'] ?? obj['id'] ?? obj['href'];
    if (typeof candidate === 'string') return extractRecordId(candidate);
